python3 -c "
import pandas as pd
import json

LABEL_LOG = '/root/capsule/code/sessions/v3_S11_roi_quality/outputs/roi_qc_actions.jsonl'
rows = []
with open(LABEL_LOG) as f:
    for line in f:
        line = line.strip()
        if line:
            try:
                rows.append(json.loads(line))
            except:
                pass
log = pd.DataFrame(rows)

SUBJECTS = ['755252', '767018', '767022', '782149', '788406', '790322']
CLASS_NAMES = ['bad', 'bad_ok', 'good', 'merged']

def _active_labels(log, sid):
    sub = log[log['sid'].astype(str) == sid].copy()
    if sub.empty:
        return pd.DataFrame(columns=['hcr_id', 'label'])
    tomb_ids = set()
    if (sub['label'] == '_undone_').any():
        for _, r in sub[sub['label'] == '_undone_'].iterrows():
            ub = r.get('undoes') or {}
            try:
                tomb_ids.add(int(ub.get('hcr_id', -1)))
            except:
                pass
    sub = sub[sub['label'].isin(['good', 'bad', 'bad_ok', 'merged', 'unsure'])]
    sub = sub[~sub['hcr_id'].astype(int).isin(tomb_ids)]
    if 'ts' in sub.columns:
        sub = sub.sort_values('ts')
    sub = sub.drop_duplicates(subset=['hcr_id'], keep='last')
    return sub[['hcr_id', 'label']].reset_index(drop=True)

total = 0
for sid in SUBJECTS:
    al = _active_labels(log, sid)
    vc = al['label'].value_counts().to_dict()
    n = len(al[al['label'].isin(CLASS_NAMES)])
    total += n
    print(f'{sid}: total={len(al)} active_4class={n} | ' + ' | '.join(f'{c}={vc.get(c,0)}' for c in CLASS_NAMES+[\"unsure\"]))
print(f'Grand total active 4-class labels: {total}')
"
